using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we configured HasDiscriminator("Discriminator")
        // to preserve the legacy property name. Without that, EF Core 9 would use "$type" and
        // this query would silently return zero results.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports synchronous I/O — ToList() throws.
        // Use async equivalents instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

